openscad:
$fn = 60;
case_diameter = 40; // [30:1:60]
case_height = 8; // [5:1:15]
dial_diameter = 36; // [28:1:58]
dial_thickness = 2; // [1:0.5:4]
marker_length = 3; // [2:0.5:6]
marker_width = 1.5; // [1:0.5:3]
hand_length_h = 10; // [6:1:18]
hand_length_m = 14; // [8:1:20]
hand_width = 1.2; // [0.8:0.2:2.5]
hand_thickness = 1.5; // [0.5:0.5:3]

color("black")
cylinder(h=case_height, d=case_diameter, center=true);

translate([0,0,case_height/2])
color("white")
cylinder(h=dial_thickness, d=dial_diameter, center=true);

for (i = [0:11]) {
    angle = i * 30;
    rotate([0,0,angle])
    translate([dial_diameter/2 - marker_length/2 - 1, 0, case_height/2 + dial_thickness/2 + 0.1])
    color("black")
    cube([marker_length, marker_width, dial_thickness], center=true);
}

translate([0,0,case_height/2 + dial_thickness + 0.2])
color("black")
cube([hand_length_h, hand_width, hand_thickness], center=true);

translate([0,0,case_height/2 + dial_thickness + 0.2])
rotate([0,0,120])
color("black")
cube([hand_length_m, hand_width, hand_thickness], center=true);
